// islands/counter.island.tsx
import { useState } from "preact/hooks";

export default function Counter({ initial = 0 }: { initial?: number }) {
  const [count, setCount] = useState(initial);
  return (
    <div class="flex items-center gap-4">
      <button class="btn btn-sm" onClick={() => setCount(c => c - 1)}>-</button>
      <span class="text-2xl font-bold">{count}</span>
      <button class="btn btn-sm btn-primary" onClick={() => setCount(c => c + 1)}>+</button>
    </div>
  );
}

// pages/index.tsx — use the island in a page
import Counter from "../../islands/counter.island.tsx";

export default function HomePage() {
  return (
    <div>
      <h1>Home</h1>
      <Counter initial={5} />
    </div>
  );
}

// islands/live-chart.island.tsx
export const howl = { ssr: false };

export default function LiveChart() {
  // This component never runs on the server.
  // It renders blank during SSR and activates after hydration.
  const data = useLiveData();
  return <Chart data={data} />;
}

import { ClientOnly } from "@hushkey/howl";

export default function Page() {
  return (
    <div>
      <h1>Server-rendered heading</h1>
      <ClientOnly>
        {() => <BrowserOnlyWidget />}
      </ClientOnly>
    </div>
  );
}

import { signal } from "@preact/signals";

const count = signal(0);

export default function ReactiveCounter() {
  return (
    <button onClick={() => count.value++}>
      Clicked {count} times
    </button>
  );
}
